1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	} as const;
9	
10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	export type Customer = { yearsWithMHPCO: number };
14	export type QuoteOptions = { isFollowUp?: boolean };
15	
16	const BLOCK_SIZE = 3;
17	const BLOCK_PREMIUM = 60;
18	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
26	const PROCESSING_FEE = 5;
27	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
28	const DEDUCTIBLE = 100;
29	
30	function itemSurcharge(item: Item): number {
31	  const base = BASE_PREMIUM[item.type];
32	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
33	  const enchantment =
34	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
35	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
36	      : 0;
37	  return cursed + enchantment;
38	}
39	
40	export function calculatePayout(policy: { items: Item[] }, damages: { itemType: ItemType; amount: number }[]): number {
41	  const totalPayout = damages.reduce(
42	    (sum, damage) => sum + damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE - DEDUCTIBLE,
43	    0,
44	  );
45	  return Math.floor(totalPayout);
46	}
47	
48	export function calculatePremium(items: Item[], customer?: Customer, options?: QuoteOptions): number {
49	  const groups = new Map<ItemType, number>();
50	  let totalSurcharge = 0;
51	  for (const item of items) {
52	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
53	    totalSurcharge += itemSurcharge(item);
54	  }
55	
56	  let basePremiumTotal = 0;
57	  for (const [type, count] of groups) {
58	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
59	      basePremiumTotal += BLOCK_PREMIUM;
60	    } else {
61	      basePremiumTotal += count * BASE_PREMIUM[type];
62	    }
63	  }
64	  let policyPremium = basePremiumTotal;
65	  if (customer && customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
66	    policyPremium *= 1 - LOYALTY_DISCOUNT_RATE;
67	  }
68	  policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE_RATE;
69	  if (options?.isFollowUp) {
70	    policyPremium *= 1 - FOLLOW_UP_DISCOUNT_RATE;
71	  }
72	  return Math.ceil(policyPremium + totalSurcharge + PROCESSING_FEE);
73	}
